package com.google.gson.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.*;
import org.junit.jupiter.api.Test;

class TypeToken_getTypeTokenTypeArgument_Test {

  // Helper subclass to create a direct subclass of TypeToken with a concrete type argument
  static class StringTypeToken extends TypeToken<String> {}

  // Helper subclass to create a raw TypeToken subclass (no type argument)
  static class RawTypeToken extends TypeToken {}

  // Helper subclass to create an indirect subclass of TypeToken
  static class IndirectTypeToken extends StringTypeToken {}

  @Test
  void test_getTypeTokenTypeArgument_directParameterizedType() throws Exception {
    TypeToken<String> token = new StringTypeToken();
    Method method = TypeToken.class.getDeclaredMethod("getTypeTokenTypeArgument");
    method.setAccessible(true);
    Type typeArgument = (Type) method.invoke(token);
    assertEquals(String.class, typeArgument);
  }

  @Test
  void test_getTypeTokenTypeArgument_rawTypeToken_throws() throws Exception {
    RawTypeToken rawToken = new RawTypeToken();
    Method method = TypeToken.class.getDeclaredMethod("getTypeTokenTypeArgument");
    method.setAccessible(true);

    IllegalStateException ex = assertThrows(IllegalStateException.class, () -> {
      try {
        method.invoke(rawToken);
      } catch (InvocationTargetException e) {
        throw e.getCause();
      }
    });
    assertTrue(ex instanceof IllegalStateException);
    assertTrue(ex.getMessage().contains("TypeToken must be created with a type argument"));
  }

  @Test
  void test_getTypeTokenTypeArgument_indirectSubclass_throws() throws Exception {
    IndirectTypeToken indirectToken = new IndirectTypeToken();
    Method method = TypeToken.class.getDeclaredMethod("getTypeTokenTypeArgument");
    method.setAccessible(true);

    IllegalStateException ex = assertThrows(IllegalStateException.class, () -> {
      try {
        method.invoke(indirectToken);
      } catch (InvocationTargetException e) {
        throw e.getCause();
      }
    });
    assertTrue(ex instanceof IllegalStateException);
    assertEquals("Must only create direct subclasses of TypeToken", ex.getMessage());
  }

  @Test
  void test_getTypeTokenTypeArgument_parameterizedTypeRawTypeNotTypeToken() throws Exception {
    // Create a ParameterizedType with raw type != TypeToken.class
    ParameterizedType fakeParameterizedType = mock(ParameterizedType.class);
    when(fakeParameterizedType.getRawType()).thenReturn(String.class);
    when(fakeParameterizedType.getActualTypeArguments()).thenReturn(new Type[] {String.class});

    // Create a dynamic proxy for Class that overrides getGenericSuperclass()
    Class<?> fakeClassProxy = (Class<?>) Proxy.newProxyInstance(
        ClassLoader.getSystemClassLoader(),
        new Class<?>[] { Class.class },
        (proxy, method, args) -> {
          if ("getGenericSuperclass".equals(method.getName())) {
            return fakeParameterizedType;
          }
          // fallback to default Object methods or throw UnsupportedOperationException
          if (method.getDeclaringClass() == Object.class) {
            return method.invoke(this, args);
          }
          throw new UnsupportedOperationException("Method " + method.getName() + " is not supported");
        });

    // Instead of overriding getClass() (which is final), create a subclass that overrides getClass()
    // is impossible, so we create a subclass of TypeToken with a custom getClass method via reflection

    // To simulate getClass() returning a fake Class, create a subclass with overridden getGenericSuperclass()
    // by creating an anonymous subclass of TypeToken with a custom getGenericSuperclass() via a subclass of ClassLoader

    // Instead, as a simpler approach, create a subclass of TypeToken with an overridden getClass method via a separate helper class

    // We cannot override getClass(), so instead we create a subclass of TypeToken with a custom class loader
    // that returns a fake generic superclass.

    // Alternative approach: create a subclass of TypeToken with a custom generic superclass.

    // We can create a subclass of TypeToken with a custom generic superclass by using a dynamic proxy for TypeToken's getClass() method is impossible,
    // so instead, create a subclass of TypeToken with a generic superclass of a parameterized type whose raw type != TypeToken.class.

    // We can do this by creating a subclass with a generic superclass that is a parameterized type with raw type != TypeToken.class.

    // Create a new class dynamically is complicated; instead, create a subclass of TypeToken with a generic superclass of StringTypeToken

    // But that would test the indirect subclass case, not this case.

    // So instead, create an anonymous subclass of TypeToken with a custom generic superclass:

    TypeToken<String> tokenWithFakeSuperclass = new TypeToken<String>() {
      @Override
      public Class<?> getClass() {
        // Return a proxy Class that returns fakeParameterizedType for getGenericSuperclass()
        return (Class<?>) Proxy.newProxyInstance(
            ClassLoader.getSystemClassLoader(),
            new Class<?>[] { Class.class },
            (proxy, method, args) -> {
              if ("getGenericSuperclass".equals(method.getName())) {
                return fakeParameterizedType;
              }
              if (method.getDeclaringClass() == Object.class) {
                return method.invoke(this, args);
              }
              throw new UnsupportedOperationException("Method " + method.getName() + " is not supported");
            });
      }
    };

    Method method = TypeToken.class.getDeclaredMethod("getTypeTokenTypeArgument");
    method.setAccessible(true);

    IllegalStateException ex = assertThrows(IllegalStateException.class, () -> {
      try {
        method.invoke(tokenWithFakeSuperclass);
      } catch (InvocationTargetException e) {
        throw e.getCause();
      }
    });
    assertTrue(ex instanceof IllegalStateException);
    assertEquals("Must only create direct subclasses of TypeToken", ex.getMessage());
  }
}
